//vip.opstream17.com/20251125/24187_b2769ab7/index.m3u8"},{"name":"25","slug":"25","filename":"Pháp Võng Truy Kích tập 25 (tiếng Việt) # Tạ Thiên Hoa, Dương Di, Trần Mẫn Chi # TVB 2012 # TVB 2012","link_embed":"https://vip.opstream17.com/share/92f55e5c0005f88cb73fe7a338842a4f","link_m3u8":"https://vip.opstream17.com/20251125/24188_92f55e5c/index.m3u8"},{"name":"26","slug":"26","filename":"Pháp Võng Truy Kích tập 26 (tiếng Việt) # Tạ Thiên Hoa, Dương Di, Trần Mẫn Chi # TVB 2012 # TVB 2012","link_embed":"https://vip.opstream17.com/share/d778dda0358a70c62a4ee6e61f33829d","link_m3u8":"https://vip.opstream17.com/20251125/24189_d778dda0/index.m3u8"}]}],"time":"40 phút/tập","description":"<p>Luật sư Cam Tổ Tán và kiểm sát viên hình sự Huống Thiên Lam vốn là một đôi tình nhân. Do một lần cầu hôn thất bại đã đưa họ đến con đường chia tay. Nhưng định mệnh trớ trêu, Tổ Tán lại phải chạm mặt với Thiên Lam khi anh chuyển sang làm kiểm sát viên. Nhưng với cách thức làm việc khác nhau cùng với sự xen vào của cô thư ký Chúc Song Duyệt, cơ hội tái hơp giữa hai người dường như là không thể có. Thế nhưng đối với lẩn cẩu hôn đó, Tổ Tán vẫn luôn cảm thấy ấm ức trong lòng, không biết rằng Thiên Lam thực sự có lý do riêng... Mặt khác, cha của Tổ Tán là Cam Bảo Tường có đứa con nuôi là Cam Ba Địa, hai người thân như anh em ruột. Ba Địa là cảnh sát tổ trọng án nên thường có cơ hội làm việc chung với Tổ Tán. Trong một lần hành động, Địa quen biết và dẩn dẩn có tình cảm với cô cảnh sát chìm Ngải Mỹ Thần. Tuy biết Mỹ Thẩn đã có hôn phu, Ba Địa vẫn bất chấp tất cả ra sức theo đuổi cô.</p>","tmdb":{"type":"tv","id":"109709","season":1,"vote_average":0,"vote_count":0},"modified":"2025-11-28T14:38:52.000Z"},{"id":"692951aca3ee3859477c205e","_id":"692951aca3ee3859477c205e","title":"Hoán Đổi Chân Tướng","origin_name":"Take Two","slug":"hoan-doi-chan-tuong","thumb":"/uploads/movies/hoan-doi-chan-tuong-thumb.jpg","poster":"","year":2021,"type":"series","genre":[{"id":"620f3d2b91fa4af90ab697fe","name":